create table if not exists agras_importacoes (id uuid primary key default gen_random_uuid(), user_id uuid, fonte text not null, arquivo_nome text, arquivo_tipo text, arquivo_hash text, status text not null default 'pendente', total_linhas integer, linhas_validas integer, linhas_com_erro integer, erro text, metadados jsonb, criado_em timestamptz default now(), processado_em timestamptz);
create index if not exists idx_agras_importacoes_user_id on agras_importacoes(user_id);
create index if not exists idx_agras_importacoes_arquivo_hash on agras_importacoes(arquivo_hash);
create table if not exists agras_operacoes (id uuid primary key default gen_random_uuid(), user_id uuid, cliente_id uuid, fazenda_id uuid, talhao_id uuid, operador_id uuid, drone_id uuid, importacao_id uuid references agras_importacoes(id), tipo_operacao text default 'pulverizacao', data_inicio timestamptz, data_fim timestamptz, area_planejada_ha numeric, area_executada_ha numeric, volume_planejado_l numeric, volume_executado_l numeric, taxa_planejada_l_ha numeric, taxa_executada_l_ha numeric, status text default 'importada', origem_dados text, criado_em timestamptz default now());
create table if not exists agras_voos (id uuid primary key default gen_random_uuid(), operacao_id uuid references agras_operacoes(id), importacao_id uuid references agras_importacoes(id), drone_id uuid, bateria_id uuid, operador_id uuid, numero_serie_drone text, numero_serie_bateria text, modelo_agras text, inicio timestamptz, fim timestamptz, duracao_segundos integer, distancia_m numeric, area_aplicada_ha numeric, volume_aplicado_l numeric, taxa_aplicacao_l_ha numeric, velocidade_media_ms numeric, velocidade_maxima_ms numeric, altura_media_m numeric, bateria_inicial_pct numeric, bateria_final_pct numeric, bateria_consumida_pct numeric, modo_operacao text, origem_linha integer, criado_em timestamptz default now());
create table if not exists agras_trajetoria_pontos (id uuid primary key default gen_random_uuid(), voo_id uuid references agras_voos(id) on delete cascade, timestamp timestamptz, sequencia integer, latitude numeric, longitude numeric, altitude_m numeric, velocidade_ms numeric, bateria_pct numeric, spray_ligado boolean, vazao_l_min numeric, volume_acumulado_l numeric, area_acumulada_ha numeric, largura_faixa_m numeric, heading_graus numeric, fonte text, criado_em timestamptz default now());
create table if not exists agras_eventos_operacionais (id uuid primary key default gen_random_uuid(), voo_id uuid references agras_voos(id) on delete cascade, tipo_evento text not null, inicio timestamptz, fim timestamptz, duracao_segundos integer, area_ha numeric, volume_l numeric, bateria_consumida_pct numeric, distancia_m numeric, velocidade_media_ms numeric, observacao text, confianca numeric, criado_em timestamptz default now());
create table if not exists agras_metricas_voo (id uuid primary key default gen_random_uuid(), voo_id uuid references agras_voos(id) on delete cascade, tempo_total_segundos integer, tempo_pulverizando_segundos integer, tempo_manobrando_segundos integer, tempo_deslocando_segundos integer, tempo_parado_segundos integer, tempo_retorno_base_segundos integer, eficiencia_operacional_pct numeric, produtividade_real_ha_h numeric, produtividade_pulverizando_ha_h numeric, bateria_por_ha_pct numeric, volume_por_ha_l numeric, distancia_por_ha_m numeric, manobra_pct numeric, parado_pct numeric, indice_manejo numeric, diagnostico text, alertas jsonb, criado_em timestamptz default now());
create table if not exists agras_relatorios (id uuid primary key default gen_random_uuid(), operacao_id uuid references agras_operacoes(id), user_id uuid, titulo text, resumo jsonb, diagnosticos jsonb, criado_em timestamptz default now());
create index if not exists idx_agras_operacoes_user_id on agras_operacoes(user_id);
create index if not exists idx_agras_voos_importacao_id on agras_voos(importacao_id);
create index if not exists idx_agras_voos_operacao_id on agras_voos(operacao_id);
create index if not exists idx_agras_voos_inicio on agras_voos(inicio);
create index if not exists idx_agras_trajetoria_pontos_voo_id on agras_trajetoria_pontos(voo_id);
create index if not exists idx_agras_eventos_operacionais_voo_id on agras_eventos_operacionais(voo_id);
create index if not exists idx_agras_eventos_operacionais_tipo_evento on agras_eventos_operacionais(tipo_evento);
